const state = $getWorkflowStaticData('global');
state.currentTaskId = null;
state.errorBackoff = false;
return $input.all();

const item = $input.item;
const taskData = item.json.taskData || {};
const units = Array.isArray(taskData.units)
  ? taskData.units
  : Array.from({ length: taskData.totalUnits || 0 }, (_, i) => ({ index: i }));
const batchSize = taskData.batchSize || 10;

if (!units.length) {
  // No units provided; return a single placeholder item
  return [{ json: { ...item.json, unitIndex: 0, totalUnits: 0, batchSize } }];
}

return units.map((unit, idx) => ({
  json: {
    ...item.json,
    unit,
    unitIndex: idx,
    totalUnits: units.length,
    batchSize
  }
}));

const items = $input.all();
const started = Date.now();
// TODO: Process each unit in this batch
// Example: call an API, transform data, write to DB, etc.
const durationMs = Date.now() - started;
for (const item of items) {
  item.json.batchDurationMs = durationMs;
}
return items;

const items = $input.all();
const now = Date.now();
for (const item of items) {
  const taskData = item.json.taskData || {};
  const leaseExpiresAt = taskData.leaseExpiresAt || taskData.lease_expires_at || item.json.leaseExpiresAt || null;
  const remainingMs = leaseExpiresAt ? new Date(leaseExpiresAt).getTime() - now : null;
  const batchMs = item.json.batchDurationMs || 0;
  const bufferMs = taskData.leaseBufferMs || Math.max(5000, batchMs);
  const thresholdMs = batchMs + bufferMs;
  item.json.remainingLeaseMs = remainingMs;
  item.json.heartbeatThresholdMs = thresholdMs;
  item.json.shouldExtendLease = remainingMs === null ? true : remainingMs < thresholdMs;
  item.json.extendByInterval = taskData.extendByInterval || '5 minutes';
}
return items;

